HTML = '<!DOCTYPE html>\n<html lang="hi">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>वेद ज्ञान — चारों वेदों का परिचय</title>\n<link href="https://fonts.googleapis.com/css2?family=Tiro+Devanagari+Sanskrit:ital@0;1&family=Noto+Sans+Devanagari:wght@400;500;600&display=swap" rel="stylesheet">\n<style>\n  :root {\n    --saffron: #E8621A;\n    --saffron-light: #FDF0E8;\n    --gold: #C8900A;\n    --gold-light: #FDF6E3;\n    --cream: #FAF6EF;\n    --ink: #1C1409;\n    --ink-soft: #4A3728;\n    --ink-muted: #8B7355;\n    --border: rgba(200,144,10,0.2);\n    --border-strong: rgba(200,144,10,0.45);\n    --white: #FFFFFF;\n    --radius: 12px;\n    --radius-sm: 8px;\n  }\n  * { box-sizing: border-box; margin: 0; padding: 0; }\n  body { font-family: \'Noto Sans Devanagari\', sans-serif; background: var(--cream); color: var(--ink); min-height: 100vh; }\n\n  .header { background: var(--white); border-bottom: 1px solid var(--border-strong); padding: 1.25rem 2rem; display: flex; align-items: center; gap: 16px; position: sticky; top: 0; z-index: 100; }\n  .header-om { font-family: \'Tiro Devanagari Sanskrit\', serif; font-size: 32px; color: var(--saffron); line-height: 1; }\n  .header-text h1 { font-size: 20px; font-weight: 600; color: var(--ink); letter-spacing: 0.5px; }\n  .header-text p { font-size: 12px; color: var(--ink-muted); margin-top: 2px; }\n\n  .container { max-width: 900px; margin: 0 auto; padding: 2rem 1.5rem; }\n\n  .veda-tabs { display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; margin-bottom: 1.5rem; }\n  .tab-btn { background: var(--white); border: 1px solid var(--border); border-radius: var(--radius); padding: 14px 8px; cursor: pointer; text-align: center; transition: all 0.18s; font-family: \'Noto Sans Devanagari\', sans-serif; }\n  .tab-btn:hover { border-color: var(--border-strong); background: var(--gold-light); }\n  .tab-btn.active { border-width: 2px; }\n  .tab-icon { font-size: 24px; display: block; margin-bottom: 5px; }\n  .tab-name { font-size: 14px; font-weight: 600; color: var(--ink); }\n  .tab-sub { font-size: 11px; color: var(--ink-muted); margin-top: 3px; }\n\n  .progress-bar { height: 3px; background: var(--border); border-radius: 2px; margin-bottom: 1.5rem; overflow: hidden; }\n  .progress-fill { height: 100%; border-radius: 2px; transition: width 0.35s ease; }\n\n  .card { background: var(--white); border: 1px solid var(--border); border-radius: var(--radius); padding: 1.5rem; margin-bottom: 1rem; }\n\n  .veda-header { display: flex; gap: 18px; align-items: flex-start; padding-bottom: 1.25rem; border-bottom: 1px solid var(--border); margin-bottom: 1.25rem; }\n  .veda-emblem { width: 60px; height: 60px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 28px; flex-shrink: 0; }\n  .veda-meta h2 { font-size: 20px; font-weight: 600; margin-bottom: 5px; }\n  .veda-meta p { font-size: 13px; color: var(--ink-soft); line-height: 1.8; }\n  .badges { display: flex; flex-wrap: wrap; gap: 6px; margin-top: 8px; }\n  .badge { font-size: 11px; padding: 3px 10px; border-radius: 20px; font-weight: 500; }\n\n  .section-label { font-size: 12px; color: var(--ink-muted); font-weight: 500; letter-spacing: 0.5px; margin-bottom: 10px; }\n  .section-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px; margin-bottom: 1.25rem; }\n  .section-card { background: var(--cream); border: 1px solid var(--border); border-radius: var(--radius-sm); padding: 12px 10px; cursor: pointer; transition: all 0.15s; text-align: center; font-family: \'Noto Sans Devanagari\', sans-serif; }\n  .section-card:hover { border-color: var(--border-strong); }\n  .section-card.active { border-width: 2px; }\n  .section-card-icon { font-size: 18px; margin-bottom: 5px; }\n  .section-card-name { font-size: 12px; font-weight: 600; color: var(--ink); }\n  .section-card-sub { font-size: 10px; color: var(--ink-muted); margin-top: 2px; }\n\n  .detail-box { background: var(--cream); border-left: 3px solid var(--saffron); border-radius: 0 var(--radius-sm) var(--radius-sm) 0; padding: 1rem 1.25rem; }\n  .detail-box h3 { font-size: 14px; font-weight: 600; margin-bottom: 7px; color: var(--ink); }\n  .detail-box p { font-size: 13px; color: var(--ink-soft); line-height: 1.9; }\n\n  .upanishad-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 10px; margin-top: 12px; }\n  .up-card { background: var(--white); border: 1px solid var(--border); border-radius: var(--radius-sm); padding: 12px 14px; cursor: pointer; transition: all 0.15s; }\n  .up-card:hover { border-color: var(--border-strong); background: var(--gold-light); }\n  .up-card.active { border-width: 2px; }\n  .up-card-title { font-size: 13px; font-weight: 600; margin-bottom: 4px; }\n  .up-card-sub { font-size: 11px; color: var(--ink-muted); }\n  .up-detail { margin-top: 12px; background: var(--cream); border-radius: var(--radius-sm); padding: 14px 16px; border-left: 3px solid var(--saffron); }\n  .up-detail h4 { font-size: 13px; font-weight: 600; margin-bottom: 6px; }\n  .up-detail p { font-size: 13px; color: var(--ink-soft); line-height: 1.9; }\n  .up-mahavakya { font-family: \'Tiro Devanagari Sanskrit\', serif; font-size: 15px; margin: 8px 0 4px; color: var(--ink); }\n  .up-mahavakya-meaning { font-size: 12px; color: var(--ink-muted); }\n\n  .hymn-label { font-size: 12px; color: var(--ink-muted); font-weight: 500; margin-bottom: 10px; }\n  .hymn-box { border: 1px solid var(--border-strong); border-radius: var(--radius-sm); padding: 1.25rem; }\n  .hymn-sanskrit { font-family: \'Tiro Devanagari Sanskrit\', serif; font-size: 16px; color: var(--ink); line-height: 2; margin-bottom: 10px; }\n  .hymn-divider { height: 1px; background: var(--border-strong); margin-bottom: 10px; }\n  .hymn-meaning { font-size: 13px; color: var(--ink-soft); line-height: 1.8; }\n  .hymn-source { font-size: 11px; color: var(--ink-muted); margin-top: 8px; font-style: italic; }\n\n  .concept-chips { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 1rem; }\n  .chip { font-size: 12px; padding: 6px 14px; border-radius: 20px; background: var(--cream); border: 1px solid var(--border-strong); color: var(--ink-soft); cursor: pointer; transition: all 0.15s; font-family: \'Noto Sans Devanagari\', sans-serif; }\n  .chip:hover { background: var(--gold-light); color: var(--ink); }\n  .chip.active { background: var(--gold-light); font-weight: 600; }\n  .concept-empty { font-size: 12px; color: var(--ink-muted); font-style: italic; }\n\n  .nav-row { display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px; }\n  .dots { display: flex; gap: 7px; }\n  .dot { width: 8px; height: 8px; border-radius: 50%; background: var(--border-strong); cursor: pointer; transition: background 0.15s; }\n  .dot.active { background: var(--saffron); }\n\n  .ask-btn { width: 100%; padding: 13px; border: 1.5px solid; border-radius: var(--radius-sm); font-size: 14px; font-weight: 600; cursor: pointer; font-family: \'Noto Sans Devanagari\', sans-serif; transition: background 0.15s; margin-top: 4px; }\n\n  .mandala-bg { text-align: center; font-size: 80px; opacity: 0.04; position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%); pointer-events: none; z-index: 0; user-select: none; }\n\n  .facts-row { display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; margin-bottom: 1.25rem; }\n  .fact-box { background: var(--cream); border: 1px solid var(--border); border-radius: var(--radius-sm); padding: 10px 12px; text-align: center; }\n  .fact-num { font-size: 20px; font-weight: 600; }\n  .fact-label { font-size: 10px; color: var(--ink-muted); margin-top: 2px; }\n\n  @media (max-width: 600px) {\n    .veda-tabs { grid-template-columns: repeat(2, 1fr); }\n    .section-grid { grid-template-columns: repeat(2, 1fr); }\n    .upanishad-grid { grid-template-columns: 1fr; }\n    .facts-row { grid-template-columns: repeat(3, 1fr); }\n    .veda-header { flex-direction: column; }\n    .container { padding: 1rem; }\n    .header { padding: 1rem; }\n  }\n</style>\n</head>\n<body>\n\n<div class="mandala-bg">ॐ</div>\n\n<header class="header">\n  <div class="header-om">ॐ</div>\n  <div class="header-text">\n    <h1>वेद ज्ञान</h1>\n    <p>चारों वेदों की आसान जानकारी — हिंदी में</p>\n  </div>\n</header>\n\n<div class="container">\n  <div class="veda-tabs" id="vedaTabs"></div>\n  <div class="progress-bar"><div class="progress-fill" id="progressFill"></div></div>\n  <div id="mainContent"></div>\n</div>\n\n<script>\nconst VEDAS = [\n  {\n    id: \'rig\',\n    name: \'ऋग्वेद\',\n    sub: \'स्तुतियों का वेद\',\n    icon: \'🔥\',\n    color: \'#BA7517\', bg: \'#FDF6E3\', border: \'#C8900A\', accent: \'#BA7517\',\n    parichay: \'यह सबसे पुराना वेद है। इसमें देवताओं की प्रशंसा में लिखे गए भजन (ऋचाएं) हैं। यह करीब 1500 ईसा पूर्व लिखा गया था।\',\n    facts: [{ num: \'1028\', label: \'सूक्त (भजन)\' }, { num: \'10,552\', label: \'ऋचाएं (श्लोक)\' }, { num: \'10\', label: \'मंडल (भाग)\' }],\n    devata: \'अग्नि, इंद्र, वरुण, सूर्य\',\n    badges: [\'सबसे पुराना वेद\', \'1028 भजन\', \'10 मंडल\'],\n    sections: [\n      { name: \'मंडल\', sub: \'10 मुख्य भाग\', icon: \'📖\' },\n      { name: \'संहिता\', sub: \'मूल मंत्र\', icon: \'📜\' },\n      { name: \'ब्राह्मण\', sub: \'पूजा विधि\', icon: \'🕯\' },\n      { name: \'उपनिषद\', sub: \'दर्शन और ज्ञान\', icon: \'🧘\' },\n    ],\n    sectionDetails: [\n      { title: \'मंडल — 10 मुख्य भाग\', text: \'ऋग्वेद 10 मंडलों में बंटा हुआ है। मंडल 2 से 7 सबसे पुराने हैं — ये अलग-अलग ऋषि परिवारों ने लिखे थे। मंडल 1, 8, 9, 10 बाद में जोड़े गए। हर मंडल में कई सूक्त (भजन समूह) होते हैं।\' },\n      { title: \'संहिता — मूल मंत्र संग्रह\', text: \'संहिता माने वेद का वह हिस्सा जिसमें सभी मंत्र इकट्ठे हैं। ऋग्वेद की संहिता में 10,552 श्लोक हैं। ज़्यादातर मंत्र अग्नि देव और इंद्र देव की प्रशंसा में हैं।\' },\n      { title: \'ब्राह्मण — पूजा विधि की किताबें\', text: \'ये किताबें बताती हैं कि यज्ञ कैसे करना है और हर मंत्र का क्या मतलब है। ऋग्वेद की ब्राह्मण किताब का नाम "ऐतरेय ब्राह्मण" है। इसमें सोम यज्ञ और राजा के राज्याभिषेक की विधि है।\' },\n      { title: \'उपनिषद — ज्ञान की बातें\', text: \'ऋग्वेद से जुड़े मुख्य उपनिषद: ऐतरेय उपनिषद — इसमें बताया गया है कि सृष्टि कैसे बनी और आत्मा क्या है। यह बहुत सरल और छोटा उपनिषद है — केवल 3 अध्याय। कौषीतकि उपनिषद — इसमें प्राण (जीवन शक्ति) और ब्रह्मन के बारे में बताया गया है।\' },\n    ],\n    upanishads: [\n      {\n        name: \'ऐतरेय उपनिषद\',\n        sub: \'3 अध्याय • ऋग्वेद\',\n        detail: \'यह बहुत छोटा और सरल उपनिषद है। इसमें बताया गया है कि शुरू में सिर्फ आत्मा थी। फिर उसने मन, फिर आकाश, फिर हवा, फिर पानी और फिर धरती बनाई। सबसे बड़ी सीख यह है — "प्रज्ञानम् ब्रह्म" यानी "ज्ञान ही ईश्वर है।"\',\n        mahavakya: \'प्रज्ञानम् ब्रह्म\',\n        mahavakya_arth: \'"ज्ञान (चेतना) ही ब्रह्म है" — यह वेदांत के 4 महावाक्यों में से एक है।\'\n      },\n      {\n        name: \'कौषीतकि उपनिषद\',\n        sub: \'4 अध्याय • ऋग्वेद\',\n        detail: \'इस उपनिषद में इंद्र और प्रतर्दन की कहानी है। इंद्र कहते हैं — "मुझे जानो, यही सबसे बड़ा ज्ञान है।" यहां बताया गया है कि प्राण (सांस/जीवन शक्ति) ही ब्रह्मन है। जो प्राण को समझ लेता है, वह सब कुछ समझ लेता है।\',\n        mahavakya: \'प्राणो ब्रह्म\',\n        mahavakya_arth: \'"प्राण ही ब्रह्म है" — जीवन शक्ति और परमात्मा एक ही हैं।\'\n      }\n    ],\n    hymn: {\n      sanskrit: \'अग्निमीळे पुरोहितं यज्ञस्य देवमृत्विजम्।\\nहोतारं रत्नधातमम्॥\',\n      arth: \'"मैं अग्नि देव की प्रशंसा करता हूं — जो यज्ञ के पुजारी हैं, देवताओं में श्रेष्ठ हैं, और सभी अच्छी चीजें देने वाले हैं।"\',\n      source: \'— ऋग्वेद 1.1.1 (पहली ऋचा)\'\n    },\n    concepts: [\'अग्नि देव\', \'इंद्र देव\', \'सोम\', \'वरुण देव\', \'ऋत (सच्चाई)\', \'गायत्री मंत्र\'],\n    conceptInfo: {\n      \'अग्नि देव\': \'अग्नि देव मनुष्यों और देवताओं के बीच दूत हैं। जब हम यज्ञ में आहुति देते हैं, तो अग्नि उसे देवताओं तक पहुंचाती है। ऋग्वेद का पहला मंत्र इन्हीं को लिखा गया है।\',\n      \'इंद्र देव\': \'इंद्र देवताओं के राजा हैं। वे बिजली, बारिश और युद्ध के देव हैं। उन्होंने अजगर वृत्र को मारकर पानी आज़ाद किया — यह ऋग्वेद की सबसे मशहूर कहानी है।\',\n      \'सोम\': \'सोम एक पवित्र पेय था जो यज्ञ में चढ़ाया जाता था। यह देवताओं को बहुत पसंद था। सोम ताज़गी, खुशी और अमरता का प्रतीक है।\',\n      \'वरुण देव\': \'वरुण देव सत्य और न्याय के देव हैं। वे सब कुछ देखते हैं। जो गलती करके माफी मांगे, वे उसे माफ कर देते हैं।\',\n      \'ऋत (सच्चाई)\': \'ऋत माने ब्रह्मांड का सच्चा नियम — जैसे सूरज हर रोज उगता है, मौसम बदलते हैं। यही बाद में "धर्म" बना।\',\n      \'गायत्री मंत्र\': \'"ॐ भूर्भुवः स्वः तत्सवितुर्वरेण्यं भर्गो देवस्य धीमहि धियो यो नः प्रचोदयात्" — यह सूर्य देव को लिखा गया सबसे पवित्र वैदिक मंत्र है। इसका मतलब है — "हे सूर्य, हमारी बुद्धि को सही रास्ता दिखाओ।"\'\n    }\n  },\n  {\n    id: \'sama\',\n    name: \'सामवेद\',\n    sub: \'गानों का वेद\',\n    icon: \'🎵\',\n    color: \'#185FA5\', bg: \'#E8F2FC\', border: \'#378ADD\', accent: \'#185FA5\',\n    parichay: \'यह गानों का वेद है। इसके मंत्र सोम यज्ञ के दौरान गाए जाते थे। भारतीय शास्त्रीय संगीत की शुरुआत इसी वेद से हुई।\',\n    facts: [{ num: \'1875\', label: \'ऋचाएं\' }, { num: \'75\', label: \'मंत्र — सामवेद के अपने\' }, { num: \'2\', label: \'मुख्य भाग\' }],\n    devata: \'सोम, इंद्र, अग्नि\',\n    badges: [\'संगीत का वेद\', \'1875 ऋचाएं\', \'भारतीय संगीत का जन्म\'],\n    sections: [\n      { name: \'पूर्वार्चिक\', sub: \'पहला भाग\', icon: \'🎶\' },\n      { name: \'उत्तरार्चिक\', sub: \'दूसरा भाग\', icon: \'🎼\' },\n      { name: \'ब्राह्मण\', sub: \'यज्ञ की जानकारी\', icon: \'📋\' },\n      { name: \'उपनिषद\', sub: \'छांदोग्य व केन\', icon: \'🧘\' },\n    ],\n    sectionDetails: [\n      { title: \'पूर्वार्चिक — पहला भाग\', text: \'इसमें 585 ऋचाएं हैं। ज़्यादातर ऋग्वेद से ली गई हैं, लेकिन इन्हें गाने के लिए सजाया गया है। इसमें 6 अध्याय हैं और हर अध्याय अलग-अलग देवता को समर्पित है।\' },\n      { title: \'उत्तरार्चिक — दूसरा भाग\', text: \'यह बड़ा भाग है जिसमें 1,225 ऋचाएं हैं। ये सोम यज्ञ के दौरान गाई जाती थीं। हर यज्ञ के अलग-अलग हिस्से में अलग-अलग राग (धुन) गाई जाती थी।\' },\n      { title: \'ब्राह्मण — यज्ञ की पूरी जानकारी\', text: \'सामवेद की ब्राह्मण किताबें (तांड्य महाब्राह्मण, जैमिनीय ब्राह्मण) बताती हैं कि सोम यज्ञ में कब कौन सा गाना गाना है। यह बहुत विस्तार से लिखा गया है।\' },\n      { title: \'उपनिषद — गहरी बातें\', text: \'छांदोग्य उपनिषद सबसे बड़े और पुराने उपनिषदों में से एक है। इसमें "तत् त्वम् असि" (वह तुम हो) जैसी बड़ी बात कही गई है। केन उपनिषद में पूछा गया है — "आंख को कौन देखता है? कान को कौन सुनता है?" यानी — परमात्मा सब के पीछे है।\' },\n    ],\n    upanishads: [\n      {\n        name: \'छांदोग्य उपनिषद\',\n        sub: \'8 अध्याय • सामवेद • सबसे बड़ा\',\n        detail: \'यह सबसे पुराने और बड़े उपनिषदों में से एक है। इसमें "ॐ" की महिमा से शुरुआत होती है। उद्दालक आरुणि अपने बेटे श्वेतकेतु को समझाते हैं — "जैसे नमक पानी में मिल जाता है और दिखता नहीं, लेकिन हर जगह है — वैसे ही परमात्मा हर चीज़ में है।" यही "तत् त्वम् असि" की शिक्षा है।\',\n        mahavakya: \'तत् त्वम् असि\',\n        mahavakya_arth: \'"वह तुम हो" — यानी तुम्हारी आत्मा और परमात्मा एक ही हैं। यह वेदांत के 4 महावाक्यों में से एक है।\'\n      },\n      {\n        name: \'केन उपनिषद\',\n        sub: \'4 भाग • सामवेद\',\n        detail: \'केन माने "किसके द्वारा?" यह उपनिषद सवाल से शुरू होता है — "किसके कहने पर मन सोचता है? किसके कारण सांस चलती है?" जवाब है — वह परमात्मा सब चीज़ों के पीछे है, लेकिन वह खुद किसी के कारण नहीं है। इसमें इंद्र की एक मज़ेदार कहानी भी है।\',\n        mahavakya: \'केनेषितं पतति प्रेषितं मनः\',\n        mahavakya_arth: \'"किसके आदेश से मन चलता है?" — परमात्मा हर चीज़ को चलाता है।\'\n      }\n    ],\n    hymn: {\n      sanskrit: \'ॐ इत्येतदक्षरमुद्गीथमुपासीत।\\nओमिति ह्युद्गायति।\',\n      arth: \'"ॐ — इस एक अक्षर को उद्गीथ (मुख्य गान) मानकर पूजो। उद्गातृ पुजारी ॐ से ही गाना शुरू करता है।"\',\n      source: \'— छांदोग्य उपनिषद 1.1.1\'\n    },\n    concepts: [\'सामन (राग)\', \'उद्गीथ\', \'छांदोग्य\', \'तत् त्वम् असि\', \'सोम यज्ञ\', \'सात स्वर\'],\n    conceptInfo: {\n      \'सामन (राग)\': \'सामवेद के मंत्रों को राग में गाया जाता था। उद्गातृ पुजारी इन्हें पाँच स्वरों में गाते थे — यही भारतीय शास्त्रीय संगीत की शुरुआत है।\',\n      \'उद्गीथ\': \'सोम यज्ञ का सबसे ज़रूरी गाना। यह "ॐ" से शुरू होता है। छांदोग्य उपनिषद में बताया है कि उद्गीथ यानी परमात्मा का प्रतीक है।\',\n      \'छांदोग्य\': \'सामवेद का सबसे बड़ा उपनिषद। इसमें "तत् त्वम् असि" की शिक्षा है और उद्दालक-श्वेतकेतु की मशहूर कहानी है।\',\n      \'तत् त्वम् असि\': \'"वह तुम हो" — इसका मतलब है तुम्हारी आत्मा और परमात्मा अलग नहीं हैं। यह वेदांत का सबसे बड़ा सन्देश है।\',\n      \'सोम यज्ञ\': \'यह मुख्य वैदिक यज्ञ था जिसमें सोम रस चढ़ाया जाता था। सामवेद के सारे गाने इसी यज्ञ के लिए थे।\',\n      \'सात स्वर\': \'भारतीय संगीत के सात स्वर (सा, रे, ग, म, प, ध, नि) सामवेद की गायन परंपरा से आए हैं।\'\n    }\n  },\n  {\n    id: \'yajur\',\n    name: \'यजुर्वेद\',\n    sub: \'यज्ञों का वेद\',\n    icon: \'🕯\',\n    color: \'#3B6D11\', bg: \'#EAF3DE\', border: \'#639922\', accent: \'#3B6D11\',\n    parichay: \'यज्ञ की विधि बताने वाला वेद। इसमें वो मंत्र हैं जो यज्ञ करते समय बोले जाते थे। इसमें रुद्र (शिव) और विष्णु की स्तुति भी है।\',\n    facts: [{ num: \'1975+\', label: \'मंत्र\' }, { num: \'2\', label: \'मुख्य शाखाएं\' }, { num: \'40\', label: \'अध्याय (शुक्ल)\' }],\n    devata: \'रुद्र, विष्णु, इंद्र\',\n    badges: [\'यज्ञ का वेद\', \'2 शाखाएं\', \'श्री रुद्रम् का स्रोत\'],\n    sections: [\n      { name: \'कृष्ण यजुर्वेद\', sub: \'मिला-जुला रूप\', icon: \'⚫\' },\n      { name: \'शुक्ल यजुर्वेद\', sub: \'साफ मंत्र संग्रह\', icon: \'⚪\' },\n      { name: \'शतपथ ब्राह्मण\', sub: \'बड़ी किताब\', icon: \'📚\' },\n      { name: \'उपनिषद\', sub: \'बृहदारण्यक व ईश\', icon: \'🧘\' },\n    ],\n    sectionDetails: [\n      { title: \'कृष्ण यजुर्वेद — मिला-जुला रूप\', text: \'"कृष्ण" (काला) इसलिए कहते हैं क्योंकि इसमें मंत्र और उनकी व्याख्या साथ-साथ लिखी है। मुख्य शाखाएं हैं: तैत्तिरीय संहिता और मैत्रायणी संहिता। प्रसिद्ध श्री रुद्रम् इसी में है।\' },\n      { title: \'शुक्ल यजुर्वेद — साफ मंत्र संग्रह\', text: \'"शुक्ल" (सफेद) इसलिए कि मंत्र और व्याख्या अलग-अलग किताबों में हैं — ज़्यादा साफ तरीके से। दो शाखाएं हैं: वाजसनेयी और काण्व। ईशावास्योपनिषद और शतपथ ब्राह्मण इसी से हैं।\' },\n      { title: \'शतपथ ब्राह्मण — बहुत बड़ी किताब\', text: \'यह शुक्ल यजुर्वेद की सबसे ज़रूरी किताब है। इसमें वैदिक यज्ञों का पूरा तरीका लिखा है, जिसमें अग्निचयन (अग्नि की वेदी बनाना) भी शामिल है। इसमें 100 अध्याय हैं।\' },\n      { title: \'उपनिषद — दो बहुत ज़रूरी उपनिषद\', text: \'बृहदारण्यक उपनिषद — सबसे बड़ा उपनिषद। ऋषि याज्ञवल्क्य ने इसमें आत्मा की गहरी बातें बताई हैं। ईशावास्योपनिषद — सबसे छोटा (सिर्फ 18 श्लोक)। यह सिखाता है: हर जगह परमात्मा है, इसलिए लालच मत करो।\' },\n    ],\n    upanishads: [\n      {\n        name: \'बृहदारण्यक उपनिषद\',\n        sub: \'6 अध्याय • शुक्ल यजुर्वेद • सबसे बड़ा\',\n        detail: \'यह सबसे बड़ा उपनिषद है। इसमें ऋषि याज्ञवल्क्य की शिक्षाएं हैं। एक बार राजा जनक के दरबार में सबसे बड़े ज्ञानी की परीक्षा हुई। याज्ञवल्क्य जीते। उन्होंने कहा — "आत्मा को आंखों से नहीं देख सकते, मन से नहीं समझ सकते — वह देखने वाला ही है।" इसमें "नेति नेति" (न यह, न यह) से परमात्मा को समझाया गया है।\',\n        mahavakya: \'अहम् ब्रह्मास्मि\',\n        mahavakya_arth: \'"मैं ही ब्रह्म हूं" — तुम्हारी आत्मा और परमात्मा में कोई फर्क नहीं। यह वेदांत के 4 महावाक्यों में से एक है।\'\n      },\n      {\n        name: \'ईशावास्योपनिषद\',\n        sub: \'18 श्लोक • शुक्ल यजुर्वेद • सबसे छोटा\',\n        detail: \'सिर्फ 18 श्लोक, लेकिन बहुत गहरी बात। शुरुआत होती है — "ईशावास्यमिदम् सर्वम्" यानी "यह पूरी दुनिया परमात्मा से भरी है।" यह सिखाता है: काम करो लेकिन फल की चिंता मत करो। सब कुछ परमात्मा का है। महात्मा गांधी को यह सबसे पसंदीदा उपनिषद था।\',\n        mahavakya: \'ईशावास्यमिदम् सर्वम्\',\n        mahavakya_arth: \'"यह पूरा जगत परमात्मा में बसा है" — हर जगह, हर चीज़ में परमात्मा है।\'\n      }\n    ],\n    hymn: {\n      sanskrit: \'शं नो मित्रः शं वरुणः।\\nशं नो भवत्वर्यमा।\\nशं न इन्द्रो बृहस्पतिः।\\nशं नो विष्णुरुरुक्रमः॥\',\n      arth: \'"मित्र हमें खुशी दें, वरुण हमें खुशी दें, अर्यमा हम पर दया करें, इंद्र और बृहस्पति हमें आशीर्वाद दें, और बड़े कदम वाले विष्णु हम पर कृपा करें।"\',\n      source: \'— तैत्तिरीयोपनिषद, शांति पाठ\'\n    },\n    concepts: [\'अध्वर्यु\', \'श्री रुद्रम्\', \'याज्ञवल्क्य\', \'अग्निचयन\', \'ईशावास्योपनिषद\', \'नेति नेति\'],\n    conceptInfo: {\n      \'अध्वर्यु\': \'यजुर्वेद का पुजारी जो यज्ञ में सारे काम करता है — जैसे आग जलाना, आहुति देना — और हर काम के साथ यजुर्वेद के मंत्र बोलता है।\',\n      \'श्री रुद्रम्\': \'कृष्ण यजुर्वेद का बहुत प्रसिद्ध भजन जो रुद्र (शिव) को लिखा गया है। इसमें रुद्र के 108 नाम हैं। आज भी मंदिरों में बड़े प्यार से गाया जाता है।\',\n      \'याज्ञवल्क्य\': \'बृहदारण्यक उपनिषद के बड़े ऋषि। वे कहते थे — "ब्रह्म को नेति नेति से जानो।" उनकी पत्नी मैत्रेयी ने भी उनसे ब्रह्म-ज्ञान सीखा।\',\n      \'अग्निचयन\': \'शतपथ ब्राह्मण में बताया गया एक बड़ा यज्ञ जिसमें बाज के आकार की अग्नि-वेदी बनाई जाती थी — 10,800 ईंटों से। यह बहुत मुश्किल और लंबा यज्ञ था।\',\n      \'ईशावास्योपनिषद\': \'सबसे छोटा उपनिषद — सिर्फ 18 श्लोक। सिखाता है: पूरी दुनिया परमात्मा की है। बिना लालच के काम करो। गांधीजी का सबसे पसंदीदा ग्रंथ।\',\n      \'नेति नेति\': \'"न यह, न यह" — याज्ञवल्क्य का तरीका परमात्मा को समझाने का। परमात्मा किसी शब्द या रूप में नहीं बताया जा सकता, इसलिए हर चीज़ को हटाते जाओ।\'\n    }\n  },\n  {\n    id: \'atharva\',\n    name: \'अथर्ववेद\',\n    sub: \'जीवन ज्ञान का वेद\',\n    icon: \'🌿\',\n    color: \'#534AB7\', bg: \'#EEEDFE\', border: \'#7F77DD\', accent: \'#534AB7\',\n    parichay: \'यह चौथा और सबसे अलग वेद है। इसमें रोज़मर्रा की ज़िंदगी की बातें हैं — बीमारी का इलाज, घर की खुशहाली, प्यार, और गहरे सवाल। आयुर्वेद की जड़ें यहीं हैं।\',\n    facts: [{ num: \'730\', label: \'सूक्त (भजन)\' }, { num: \'6000\', label: \'श्लोक लगभग\' }, { num: \'20\', label: \'अध्याय (काण्ड)\' }],\n    devata: \'भूमि (पृथ्वी), काम, ब्रह्मन\',\n    badges: [\'चौथा वेद\', \'730 सूक्त\', \'आयुर्वेद का स्रोत\'],\n    sections: [\n      { name: \'शौनकीया\', sub: \'मुख्य संहिता\', icon: \'📗\' },\n      { name: \'पैप्पलाद\', sub: \'पुरानी संहिता\', icon: \'📕\' },\n      { name: \'गोपथ ब्राह्मण\', sub: \'एकमात्र ब्राह्मण\', icon: \'📋\' },\n      { name: \'उपनिषद\', sub: \'मुंडक व माण्डूक्य\', icon: \'🧘\' },\n    ],\n    sectionDetails: [\n      { title: \'शौनकीया — मुख्य और सबसे ज़्यादा पढ़ी जाने वाली संहिता\', text: \'इसमें 20 काण्डों (अध्यायों) में 730 सूक्त हैं। इसमें बीमारी ठीक करने के मंत्र, प्यार के मंत्र, राजा के लिए अनुष्ठान और मशहूर "पृथ्वी सूक्त" (धरती माता की प्रशंसा) है।\' },\n      { title: \'पैप्पलाद — पुरानी संहिता\', text: \'यह अथर्ववेद का और भी पुराना रूप है। यह कश्मीर की पुरानी किताबों से मिला। लंबे समय तक लोगों को लगता था कि यह खो गया है, लेकिन 20वीं सदी में यह दोबारा मिला।\' },\n      { title: \'गोपथ ब्राह्मण — एकमात्र ब्राह्मण\', text: \'यह अथर्ववेद की एकमात्र ब्राह्मण किताब है। बाकी वेदों की ब्राह्मण किताबों से यह अलग है — इसमें ज़्यादा कहानियां हैं और ब्रह्मा को सबसे बड़ा देव बताया गया है।\' },\n      { title: \'उपनिषद — दो बड़े उपनिषद\', text: \'मुंडकोपनिषद — दो तरह का ज्ञान बताता है: एक जो स्कूल में पढ़ते हैं (गणित, विज्ञान, भाषा) और एक जो परमात्मा को जानने का ज्ञान है — दूसरा ज़्यादा ज़रूरी है। माण्डूक्य उपनिषद — सिर्फ 12 श्लोक! इसमें "ॐ" के अर्थ से जागते, सपने और गहरी नींद की तीन अवस्थाएं समझाई गई हैं।\' },\n    ],\n    upanishads: [\n      {\n        name: \'मुंडकोपनिषद\',\n        sub: \'3 मुंडक • अथर्ववेद\',\n        detail: \'एक बार शौनक ऋषि ने पूछा — "क्या एक चीज़ जानने से सब कुछ पता चल जाता है?" जवाब में दो तरह का ज्ञान बताया: "अपरा विद्या" (साधारण ज्ञान जैसे वेद, गणित, भाषा) और "परा विद्या" (वह ज्ञान जिससे परमात्मा को जाना जाए)। यह उपनिषद कहता है — आत्मा किसी हथियार से नहीं कटती, आग से नहीं जलती, पानी से नहीं भीगती।\',\n        mahavakya: \'ब्रह्म वेद ब्रह्मैव भवति\',\n        mahavakya_arth: \'"जो ब्रह्म को जान लेता है, वह खुद ब्रह्म बन जाता है।"\'\n      },\n      {\n        name: \'माण्डूक्य उपनिषद\',\n        sub: \'12 श्लोक • अथर्ववेद • सबसे छोटा पर गहरा\',\n        detail: \'सिर्फ 12 श्लोक लेकिन वेदांत में सबसे ज़्यादा पढ़ा जाता है। यह "ॐ" का पूरा अर्थ बताता है: अ = जागने की अवस्था, उ = सपने की अवस्था, म = गहरी नींद, और जो मौन "ॐ" के बाद आता है — वह है "तुरीय" (चौथी अवस्था) — यही शुद्ध चेतना, यही परमात्मा है।\',\n        mahavakya: \'अयम् आत्मा ब्रह्म\',\n        mahavakya_arth: \'"यह आत्मा ही ब्रह्म है" — तुम्हारे अंदर जो है और बाहर जो है, वह एक ही है।\'\n      }\n    ],\n    hymn: {\n      sanskrit: \'माता भूमिः पुत्रोऽहं पृथिव्याः।\\nपर्जन्यः पिता स उ नः पिपर्तु॥\',\n      arth: \'"धरती मेरी माँ है, मैं उसका बेटा हूं। बारिश (पर्जन्य) मेरे पिता हैं — वे हमारा पालन करें।"\',\n      source: \'— अथर्ववेद 12.1.12 (पृथ्वी सूक्त)\'\n    },\n    concepts: [\'पृथ्वी सूक्त\', \'आयुर्वेद\', \'माण्डूक्य\', \'ॐ / AUM\', \'ब्रह्मन\', \'काम (इच्छा)\'],\n    conceptInfo: {\n      \'पृथ्वी सूक्त\': \'सभी वेदों का सबसे लंबा भजन — 63 श्लोक। यह धरती माता की तारीफ है। नदियां, पहाड़, पेड़-पौधे, मिट्टी — सबकी प्रशंसा है। यह दुनिया का सबसे पुराना पर्यावरण-प्रेम का उदाहरण है।\',\n      \'आयुर्वेद\': \'अथर्ववेद में बीमारियों के इलाज, जड़ी-बूटियों और स्वास्थ्य के मंत्र हैं। इन्हीं से आयुर्वेद (भारत की पुरानी चिकित्सा पद्धति) की शुरुआत हुई।\',\n      \'माण्डूक्य\': \'सिर्फ 12 श्लोक वाला यह उपनिषद "ॐ" और चेतना की 4 अवस्थाओं के बारे में है। अद्वैत वेदांत में इसे सबसे महत्वपूर्ण माना जाता है।\',\n      \'ॐ / AUM\': \'सबसे पवित्र ध्वनि। अ = जागना, उ = सपना, म = गहरी नींद, और बाद का मौन = तुरीय (परमात्मा)। पूरी सृष्टि इसी से बनी है।\',\n      \'ब्रह्मन\': \'वह शक्ति जो हर जगह है — आसमान में, धरती में, हम सबके अंदर भी। यह कोई व्यक्ति नहीं बल्कि शुद्ध चेतना है। जब हम यह जान लेते हैं — वही मोक्ष है।\',\n      \'काम (इच्छा)\': \'अथर्ववेद में काम-देव (प्यार के देव) के मंत्र हैं। यहां इच्छा को बुरा नहीं माना गया — यह सृष्टि की ज़रूरी शक्ति है।\'\n    }\n  }\n];\n\nlet activeVeda = 0, activeSection = 0, activeConcept = null, activeUpanishad = null;\n\nfunction renderTabs() {\n  document.getElementById(\'vedaTabs\').innerHTML = VEDAS.map((v, i) => `\n    <button class="tab-btn ${i===activeVeda?\'active\':\'\'}" onclick="setVeda(${i})"\n      style="${i===activeVeda?`border-color:${v.border};border-width:2px`:\'\'}">\n      <span class="tab-icon">${v.icon}</span>\n      <div class="tab-name" style="${i===activeVeda?`color:${v.accent}`:\'\'}"> ${v.name}</div>\n      <div class="tab-sub">${v.sub}</div>\n    </button>`).join(\'\');\n}\n\nfunction renderProgress() {\n  const el = document.getElementById(\'progressFill\');\n  el.style.width = ((activeVeda+1)/4*100)+\'%\';\n  el.style.background = VEDAS[activeVeda].accent;\n}\n\nfunction renderMain() {\n  const v = VEDAS[activeVeda];\n  const sd = v.sectionDetails[activeSection];\n  const ci = activeConcept && v.conceptInfo[activeConcept];\n\n  // upanishad section\n  const isUpanishadSection = activeSection === 3;\n  const upCards = isUpanishadSection && v.upanishads ? v.upanishads.map((u, i) => `\n    <div class="up-card ${activeUpanishad===i?\'active\':\'\'}" onclick="setUpanishad(${i})"\n      style="${activeUpanishad===i?`border-color:${v.accent};background:${v.bg}`:\'\'}">\n      <div class="up-card-title" style="${activeUpanishad===i?`color:${v.accent}`:\'\'}"> ${u.name}</div>\n      <div class="up-card-sub">${u.sub}</div>\n    </div>`).join(\'\') : \'\';\n\n  const upDetail = isUpanishadSection && activeUpanishad !== null && v.upanishads ? (() => {\n    const u = v.upanishads[activeUpanishad];\n    return `<div class="up-detail" style="border-left-color:${v.accent}">\n      <h4>${u.name}</h4>\n      <p>${u.detail}</p>\n      <div class="up-mahavakya" style="color:${v.accent}">${u.mahavakya}</div>\n      <div class="up-mahavakya-meaning">${u.mahavakya_arth}</div>\n    </div>`;\n  })() : \'\';\n\n  document.getElementById(\'mainContent\').innerHTML = `\n    <div class="card">\n      <div class="veda-header">\n        <div class="veda-emblem" style="background:${v.bg}">${v.icon}</div>\n        <div class="veda-meta">\n          <h2 style="color:${v.accent}">${v.name} <span style="font-size:14px;color:var(--ink-muted);font-weight:400">— ${v.sub}</span></h2>\n          <p>${v.parichay}</p>\n          <div class="badges">${v.badges.map(b=>`<span class="badge" style="background:${v.bg};color:${v.accent};border:1px solid ${v.border}">${b}</span>`).join(\'\')}</div>\n        </div>\n      </div>\n\n      <div class="facts-row">\n        ${v.facts.map(f=>`<div class="fact-box" style="background:${v.bg}">\n          <div class="fact-num" style="color:${v.accent}">${f.num}</div>\n          <div class="fact-label">${f.label}</div>\n        </div>`).join(\'\')}\n      </div>\n\n      <div class="nav-row">\n        <div class="section-label">खंड चुनें</div>\n        <div class="dots">${v.sections.map((_,i)=>`\n          <div class="dot ${i===activeSection?\'active\':\'\'}"\n            style="${i===activeSection?`background:${v.accent}`:\'\'}"\n            onclick="setSection(${i})"></div>`).join(\'\')}\n        </div>\n      </div>\n\n      <div class="section-grid">\n        ${v.sections.map((s,i)=>`\n          <div class="section-card ${i===activeSection?\'active\':\'\'}" onclick="setSection(${i})"\n            style="${i===activeSection?`border-color:${v.accent};background:${v.bg}`:\'\'}">\n            <div class="section-card-icon">${s.icon}</div>\n            <div class="section-card-name" style="${i===activeSection?`color:${v.accent}`:\'\'}"> ${s.name}</div>\n            <div class="section-card-sub">${s.sub}</div>\n          </div>`).join(\'\')}\n      </div>\n\n      <div class="detail-box" style="border-left-color:${v.accent}">\n        <h3>${sd.title}</h3>\n        <p>${sd.text}</p>\n      </div>\n\n      ${isUpanishadSection && v.upanishads ? `\n        <div style="margin-top:14px">\n          <div class="section-label" style="margin-bottom:10px">उपनिषद चुनें — और जानें</div>\n          <div class="upanishad-grid">${upCards}</div>\n          ${upDetail}\n        </div>` : \'\'}\n    </div>\n\n    <div class="card">\n      <div class="hymn-label">${v.name} की एक ऋचा</div>\n      <div class="hymn-box" style="background:${v.bg};border-color:${v.border}">\n        <div class="hymn-sanskrit">${v.hymn.sanskrit}</div>\n        <div class="hymn-divider" style="background:${v.border}"></div>\n        <div class="hymn-meaning">${v.hymn.arth}</div>\n        <div class="hymn-source">${v.hymn.source}</div>\n      </div>\n    </div>\n\n    <div class="card">\n      <div class="section-label" style="margin-bottom:12px">मुख्य बातें — किसी पर टैप करें</div>\n      <div class="concept-chips">\n        ${v.concepts.map(c=>`\n          <span class="chip ${activeConcept===c?\'active\':\'\'}" onclick="setConcept(\'${c}\')"\n            style="${activeConcept===c?`background:${v.bg};color:${v.accent};border-color:${v.accent}`:\'\'}">\n            ${c}\n          </span>`).join(\'\')}\n      </div>\n      ${ci ? `<div class="detail-box" style="border-left-color:${v.accent};margin-top:4px"><h3>${activeConcept}</h3><p>${ci}</p></div>`\n           : `<p class="concept-empty">किसी बात पर टैप करें और उसका मतलब जानें।</p>`}\n    </div>\n\n    <button class="ask-btn" style="border-color:${v.accent};color:${v.accent};background:${v.bg}"\n      onclick="window.open(\'https://claude.ai\',\'_blank\')">\n      ${v.name} के बारे में और जानना है? Claude से पूछें ↗\n    </button>\n  `;\n}\n\nfunction setVeda(i) { activeVeda=i; activeSection=0; activeConcept=null; activeUpanishad=null; renderTabs(); renderProgress(); renderMain(); }\nfunction setSection(i) { activeSection=i; activeConcept=null; activeUpanishad=null; renderMain(); }\nfunction setConcept(c) { activeConcept = activeConcept===c ? null : c; renderMain(); }\nfunction setUpanishad(i) { activeUpanishad = activeUpanishad===i ? null : i; renderMain(); }\n\nrenderTabs(); renderProgress(); renderMain();\n</script>\n</body>\n</html>\n'

@app.route("/")
def index():
    return HTML

@app.route("/<path:path>")
def catch_all(path):
    return HTML
